import '../lib/assembler.dart';
import '../lib/chunk_ledger.dart';
import '../lib/content_range.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final tenBytes = ContentRange.parse('bytes 100-109/200');
  check(tenBytes.length == 10, 'inclusive range length is wrong');

  final ledger = ChunkLedger(8);
  check(ledger.accept(ContentRange.parse('bytes 0-3/8')), 'initial range rejected');
  check(ledger.accept(ContentRange.parse('bytes 4-7/8')), 'adjacent range rejected');

  final assembled = assembleChunks({
    0: [0, 1, 2, 3],
    12: [12, 13, 14, 15],
    4: [4, 5, 6, 7, 8, 9, 10, 11],
  }, 16);
  check(
    assembled.join(',') == List.generate(16, (index) => index).join(','),
    'numeric offsets were assembled out of order',
  );
}
